import React, { useState, useEffect, useRef } from 'react';
import { Mic, MicOff, Send, Pause, Play, Volume2, VolumeX, User, Bot, MessageSquare, FileText, BookOpen, Bookmark, Search, ZoomIn, ZoomOut, RotateCw, Download, Upload, Speaker, PlayCircle, Square } from 'lucide-react';

interface Message {
  id: number;
  sender: 'user' | 'ai' | 'system';
  content: string;
  timestamp: Date;
  voiceUrl?: string; // URL for voice recording
  isPlaying?: boolean; // Whether voice is currently playing
}

interface Document {
  _id: string;
  name: string;
  type: 'contract' | 'evidence' | 'pleading' | 'correspondence' | 'case_file';
  pages: number;
  bookmarks?: BookmarkItem[];
  currentPage?: number;
}

interface BookmarkItem {
  id: string;
  page: number;
  label: string;
  note?: string;
}

interface VirtualBook {
  id: string;
  title: string;
  pages: number;
  currentPage: number;
  bookmarks: BookmarkItem[];
  content: string[];
}

const CourtroomSimulation: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputMessage, setInputMessage] = useState('');
  const [isRecording, setIsRecording] = useState(false);
  const [isMuted, setIsMuted] = useState(false);
  const [activeTab, setActiveTab] = useState<'chat' | 'documents' | 'notes' | 'evidence'>('chat');
  const [documents, setDocuments] = useState<Document[]>([]);
  const [virtualBooks, setVirtualBooks] = useState<VirtualBook[]>([]);
  const [selectedDocument, setSelectedDocument] = useState<Document | null>(null);
  const [selectedBook, setSelectedBook] = useState<VirtualBook | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [zoomLevel, setZoomLevel] = useState(100);
  const [bookmarks, setBookmarks] = useState<BookmarkItem[]>([]);
  const [isPlaying, setIsPlaying] = useState<number | null>(null); // ID of message currently playing
  const [mediaRecorder, setMediaRecorder] = useState<MediaRecorder | null>(null);
  const [audioChunks, setAudioChunks] = useState<Blob[]>([]);
  const [voicePlaying, setVoicePlaying] = useState<{[key: number]: boolean}>({});
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  // Auto-scroll to bottom of messages
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  // Initialize media recorder for voice input
  useEffect(() => {
    const initMediaRecorder = async () => {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        const recorder = new MediaRecorder(stream);
        recorder.ondataavailable = (event) => {
          if (event.data.size > 0) {
            setAudioChunks((prev) => [...prev, event.data]);
          }
        };
        recorder.onstop = () => {
          const audioBlob = new Blob(audioChunks, { type: 'audio/webm' });
          // In a real implementation, you would send this to your backend
          console.log('Audio recorded:', audioBlob);
          setAudioChunks([]);
        };
        setMediaRecorder(recorder);
      } catch (err) {
        console.error('Error accessing microphone:', err);
      }
    };

    initMediaRecorder();
  }, []);

  // Fetch documents from backend
  useEffect(() => {
    const fetchDocuments = async () => {
      try {
        setLoading(true);
        
        // Fetch real documents from backend API
        const response = await fetch('http://localhost:5000/api/courtroom/documents');
        const data = await response.json();
        
        if (data.success) {
          setDocuments(data.data);
        } else {
          setError('Failed to fetch documents: ' + data.message);
        }
        
        setLoading(false);
      } catch (err) {
        setError('Error fetching documents: ' + (err as Error).message);
        console.error('Error fetching documents:', err);
        setLoading(false);
      }
    };

    fetchDocuments();
  }, []);

  // Initialize virtual books
  useEffect(() => {
    // Sample virtual books for demonstration
    const sampleBooks: VirtualBook[] = [
      {
        id: 'bhagavad-gita',
        title: 'Bhagavad Gita',
        pages: 100,
        currentPage: 1,
        bookmarks: [
          { id: '1', page: 25, label: 'Duty and Responsibility', note: 'Relevant to case oath' },
          { id: '2', page: 42, label: 'Truth and Honesty', note: 'Witness testimony principles' }
        ],
        content: Array(100).fill('').map((_, i) => `Page ${i+1} content would be displayed here.`)
      },
      {
        id: 'legal-handbook',
        title: 'Legal Practitioner Handbook',
        pages: 200,
        currentPage: 1,
        bookmarks: [
          { id: '3', page: 15, label: 'Courtroom Etiquette', note: 'Proper conduct guidelines' },
          { id: '4', page: 78, label: 'Evidence Presentation', note: 'How to present evidence effectively' }
        ],
        content: Array(200).fill('').map((_, i) => `Page ${i+1} content would be displayed here.`)
      }
    ];
    
    setVirtualBooks(sampleBooks);
  }, []);

  // Fetch initial messages from backend
  useEffect(() => {
    const fetchInitialMessages = async () => {
      try {
        const response = await fetch('http://localhost:5000/api/courtroom/messages');
        const data = await response.json();
        
        if (data.success) {
          setMessages(data.data);
        } else {
          // Set default messages if fetch fails
          setMessages([
            {
              id: 1,
              sender: 'system',
              content: 'Welcome to the CourtCraft courtroom simulation. You are representing the plaintiff in a contract dispute case.',
              timestamp: new Date()
            },
            {
              id: 2,
              sender: 'ai',
              content: 'Good morning, Counsel. I am Judge Sharma presiding over this matter. Please present your opening statement.',
              timestamp: new Date()
            }
          ]);
        }
      } catch (err) {
        console.error('Error fetching initial messages:', err);
        // Set default messages if fetch fails
        setMessages([
          {
            id: 1,
            sender: 'system',
            content: 'Welcome to the CourtCraft courtroom simulation. You are representing the plaintiff in a contract dispute case.',
            timestamp: new Date()
          },
          {
            id: 2,
            sender: 'ai',
            content: 'Good morning, Counsel. I am Judge Sharma presiding over this matter. Please present your opening statement.',
            timestamp: new Date()
          }
        ]);
      }
    };

    fetchInitialMessages();
  }, []);

  const handleSendMessage = async () => {
    if (inputMessage.trim() === '') return;
    
    const newMessage: Message = {
      id: messages.length + 1,
      sender: 'user',
      content: inputMessage,
      timestamp: new Date()
    };
    
    setMessages([...messages, newMessage]);
    setInputMessage('');
    
    // Send message to backend and get AI response
    try {
      const response = await fetch('http://localhost:5000/api/courtroom/respond', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ message: inputMessage })
      });
      
      const data = await response.json();
      
      if (data.success) {
        setMessages(prev => [...prev, {...data.data, isPlaying: false}]);
      } else {
        // Fallback AI response if backend fails
        setTimeout(() => {
          const aiResponse: Message = {
            id: messages.length + 2,
            sender: 'ai',
            content: "Thank you for that statement, Counsel. The defendant would like to respond to your claims. Mr. Advocate for the defense, please present your counter-argument.",
            timestamp: new Date(),
            isPlaying: false
          };
          setMessages(prev => [...prev, aiResponse]);
        }, 2000);
      }
    } catch (err) {
      console.error('Error sending message:', err);
      // Fallback AI response if backend fails
      setTimeout(() => {
        const aiResponse: Message = {
          id: messages.length + 2,
          sender: 'ai',
          content: "Thank you for that statement, Counsel. The defendant would like to respond to your claims. Mr. Advocate for the defense, please present your counter-argument.",
          timestamp: new Date(),
          isPlaying: false
        };
        setMessages(prev => [...prev, aiResponse]);
      }, 2000);
    }
  };

  const toggleRecording = () => {
    if (isRecording) {
      // Stop recording
      if (mediaRecorder && mediaRecorder.state !== 'inactive') {
        mediaRecorder.stop();
      }
      setIsRecording(false);
    } else {
      // Start recording
      if (mediaRecorder && mediaRecorder.state === 'inactive') {
        setAudioChunks([]);
        mediaRecorder.start();
        setIsRecording(true);
      }
    }
  };

  const toggleMute = () => {
    setIsMuted(!isMuted);
  };

  const getDocumentIcon = (type: string) => {
    switch (type) {
      case 'contract': return <FileText className="w-5 h-5 text-blue-500" />;
      case 'evidence': return <FileText className="w-5 h-5 text-green-500" />;
      case 'pleading': return <FileText className="w-5 h-5 text-purple-500" />;
      case 'correspondence': return <FileText className="w-5 h-5 text-yellow-500" />;
      case 'case_file': return <FileText className="w-5 h-5 text-red-500" />;
      default: return <FileText className="w-5 h-5 text-gray-500" />;
    }
  };

  const handleDocumentSelect = (doc: Document) => {
    setSelectedDocument(doc);
    setActiveTab('documents');
  };

  const handleBookSelect = (book: VirtualBook) => {
    setSelectedBook(book);
    setActiveTab('documents');
  };

  const handlePageChange = (newPage: number) => {
    if (selectedBook) {
      const updatedBook = {
        ...selectedBook,
        currentPage: Math.max(1, Math.min(selectedBook.pages, newPage))
      };
      setSelectedBook(updatedBook);
      
      // Update in virtual books array
      setVirtualBooks(prev => 
        prev.map(b => b.id === selectedBook.id ? updatedBook : b)
      );
    }
  };

  const handleZoomIn = () => {
    setZoomLevel(prev => Math.min(prev + 25, 200));
  };

  const handleZoomOut = () => {
    setZoomLevel(prev => Math.max(prev - 25, 50));
  };

  const handleAddBookmark = () => {
    if (selectedBook) {
      const newBookmark: BookmarkItem = {
        id: Date.now().toString(),
        page: selectedBook.currentPage,
        label: `Bookmark ${selectedBook.bookmarks.length + 1}`,
        note: ''
      };
      
      const updatedBook = {
        ...selectedBook,
        bookmarks: [...selectedBook.bookmarks, newBookmark]
      };
      
      setSelectedBook(updatedBook);
      setVirtualBooks(prev => 
        prev.map(b => b.id === selectedBook.id ? updatedBook : b)
      );
    }
  };

  const handleRemoveBookmark = (bookmarkId: string) => {
    if (selectedBook) {
      const updatedBook = {
        ...selectedBook,
        bookmarks: selectedBook.bookmarks.filter(b => b.id !== bookmarkId)
      };
      
      setSelectedBook(updatedBook);
      setVirtualBooks(prev => 
        prev.map(b => b.id === selectedBook.id ? updatedBook : b)
      );
    }
  };

  const playVoice = (messageId: number) => {
    // In a real implementation, this would play the actual voice recording
    // For now, we'll just simulate playing
    setVoicePlaying(prev => ({ ...prev, [messageId]: true }));
    
    // Simulate voice playing for 3 seconds
    setTimeout(() => {
      setVoicePlaying(prev => ({ ...prev, [messageId]: false }));
    }, 3000);
  };

  const stopVoice = (messageId: number) => {
    setVoicePlaying(prev => ({ ...prev, [messageId]: false }));
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <div className="inline-block animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-indigo-600 mb-4"></div>
          <p className="text-gray-600">Loading courtroom simulation...</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center py-12">
          <div className="bg-red-100 rounded-full w-16 h-16 flex items-center justify-center mx-auto mb-4">
            <svg className="w-8 h-8 text-red-600" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path>
            </svg>
          </div>
          <h3 className="text-xl font-bold text-gray-900 mb-2">Error Loading Courtroom Simulation</h3>
          <p className="text-gray-600 mb-4">{error}</p>
          <button 
            className="bg-indigo-600 text-white px-6 py-3 rounded-lg hover:bg-indigo-700 transition duration-300 font-medium"
            onClick={() => window.location.reload()}
          >
            Try Again
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Hidden audio element for playing voices */}
      <audio ref={audioRef} />
      
      {/* Header */}
      <div className="bg-white shadow-sm">
        <div className="container mx-auto px-4 py-4">
          <div className="flex justify-between items-center">
            <div>
              <h1 className="text-2xl font-bold text-gray-900">Contract Dispute Case</h1>
              <p className="text-gray-600">Plaintiff vs. Defendant - Civil Court, Delhi</p>
            </div>
            <div className="flex items-center space-x-4">
              <div className="flex items-center bg-red-100 text-red-800 px-3 py-1 rounded-full">
                <div className="w-2 h-2 bg-red-500 rounded-full mr-2 animate-pulse"></div>
                <span className="text-sm font-medium">Recording</span>
              </div>
              <button className="bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 transition duration-300">
                End Session
              </button>
            </div>
          </div>
        </div>
      </div>

      <div className="container mx-auto px-4 py-8">
        <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
          {/* Main Courtroom Area */}
          <div className="lg:col-span-3">
            <div className="bg-white rounded-xl shadow-sm overflow-hidden">
              {/* Courtroom Visualization */}
              <div className="bg-gradient-to-b from-amber-800 to-amber-900 h-64 relative">
                <div className="absolute inset-0 flex items-center justify-center">
                  {/* Judge's Bench */}
                  <div className="bg-amber-700 w-64 h-24 rounded-lg flex items-center justify-center shadow-lg">
                    <div className="text-center">
                      <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center mx-auto mb-2">
                        <User className="w-6 h-6 text-amber-800" />
                      </div>
                      <p className="text-white font-medium">Hon. Judge Sharma</p>
                      <p className="text-amber-200 text-sm">Presiding</p>
                    </div>
                  </div>
                  
                  {/* Plaintiff Table */}
                  <div className="absolute left-8 bottom-8 bg-amber-100 w-48 h-20 rounded-lg flex items-center justify-center shadow">
                    <div className="text-center">
                      <div className="w-8 h-8 bg-indigo-600 rounded-full flex items-center justify-center mx-auto mb-1">
                        <User className="w-4 h-4 text-white" />
                      </div>
                      <p className="text-gray-900 font-medium text-sm">You (Plaintiff)</p>
                    </div>
                  </div>
                  
                  {/* Defendant Table */}
                  <div className="absolute right-8 bottom-8 bg-amber-100 w-48 h-20 rounded-lg flex items-center justify-center shadow">
                    <div className="text-center">
                      <div className="w-8 h-8 bg-red-600 rounded-full flex items-center justify-center mx-auto mb-1">
                        <User className="w-4 h-4 text-white" />
                      </div>
                      <p className="text-gray-900 font-medium text-sm">Defendant</p>
                    </div>
                  </div>
                </div>
              </div>
              
              {/* Chat Interface */}
              <div className="p-6">
                {/* Tabs */}
                <div className="flex border-b border-gray-200 mb-6">
                  <button
                    className={`pb-3 px-6 font-medium ${activeTab === 'chat' ? 'text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-500'}`}
                    onClick={() => setActiveTab('chat')}
                  >
                    <MessageSquare className="w-5 h-5 inline mr-2" />
                    Courtroom Chat
                  </button>
                  <button
                    className={`pb-3 px-6 font-medium ${activeTab === 'documents' ? 'text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-500'}`}
                    onClick={() => setActiveTab('documents')}
                  >
                    <FileText className="w-5 h-5 inline mr-2" />
                    Documents & Books
                  </button>
                  <button
                    className={`pb-3 px-6 font-medium ${activeTab === 'evidence' ? 'text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-500'}`}
                    onClick={() => setActiveTab('evidence')}
                  >
                    <Search className="w-5 h-5 inline mr-2" />
                    Evidence
                  </button>
                  <button
                    className={`pb-3 px-6 font-medium ${activeTab === 'notes' ? 'text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-500'}`}
                    onClick={() => setActiveTab('notes')}
                  >
                    <BookOpen className="w-5 h-5 inline mr-2" />
                    Notes
                  </button>
                </div>
                
                {/* Chat Tab */}
                {activeTab === 'chat' && (
                  <div className="space-y-6">
                    {/* Messages */}
                    <div className="space-y-4 max-h-96 overflow-y-auto pr-2">
                      {messages.map(message => (
                        <div 
                          key={message.id} 
                          className={`flex ${message.sender === 'user' ? 'justify-end' : 'justify-start'}`}
                        >
                          <div 
                            className={`max-w-xs lg:max-w-md px-4 py-3 rounded-2xl ${
                              message.sender === 'user' 
                                ? 'bg-indigo-600 text-white rounded-br-none' 
                                : message.sender === 'ai'
                                  ? 'bg-gray-100 text-gray-900 rounded-bl-none'
                                  : 'bg-blue-100 text-blue-900 rounded-b-none'
                            }`}
                          >
                            <div className="flex justify-between items-start">
                              <p className="text-sm">{message.content}</p>
                              <button 
                                className="ml-2 text-white opacity-70 hover:opacity-100"
                                onClick={() => message.sender === 'user' ? playVoice(message.id) : playVoice(message.id)}
                              >
                                {voicePlaying[message.id] ? (
                                  <Square className="w-4 h-4" />
                                ) : (
                                  <Speaker className="w-4 h-4" />
                                )}
                              </button>
                            </div>
                            <p className={`text-xs mt-1 ${message.sender === 'user' ? 'text-indigo-200' : 'text-gray-500'}`}>
                              {message.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                            </p>
                          </div>
                        </div>
                      ))}
                      <div ref={messagesEndRef} />
                    </div>
                    
                    {/* Input Area */}
                    <div className="flex items-end space-x-3">
                      <div className="flex-1 relative">
                        <textarea
                          value={inputMessage}
                          onChange={(e) => setInputMessage(e.target.value)}
                          onKeyDown={(e) => {
                            if (e.key === 'Enter' && !e.shiftKey) {
                              e.preventDefault();
                              handleSendMessage();
                            }
                          }}
                          placeholder="Type your response..."
                          className="w-full px-4 py-3 border border-gray-300 rounded-2xl focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent resize-none"
                          rows={2}
                        />
                      </div>
                      <div className="flex space-x-2">
                        <button
                          onClick={toggleRecording}
                          className={`p-3 rounded-full ${
                            isRecording 
                              ? 'bg-red-100 text-red-600 hover:bg-red-200' 
                              : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                          } transition duration-200`}
                        >
                          {isRecording ? <MicOff className="w-5 h-5" /> : <Mic className="w-5 h-5" />}
                        </button>
                        <button
                          onClick={handleSendMessage}
                          disabled={inputMessage.trim() === ''}
                          className="p-3 bg-indigo-600 text-white rounded-full hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition duration-200"
                        >
                          <Send className="w-5 h-5" />
                        </button>
                      </div>
                    </div>
                  </div>
                )}
                
                {/* Documents & Books Tab */}
                {activeTab === 'documents' && (
                  <div className="space-y-6">
                    {/* Document Selection */}
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      {documents.map(doc => (
                        <div 
                          key={doc._id} 
                          className={`flex items-center p-4 border rounded-lg cursor-pointer transition duration-200 ${
                            selectedDocument?._id === doc._id 
                              ? 'border-indigo-500 bg-indigo-50' 
                              : 'border-gray-200 hover:bg-gray-50'
                          }`}
                          onClick={() => handleDocumentSelect(doc)}
                        >
                          <div className="mr-4">
                            {getDocumentIcon(doc.type)}
                          </div>
                          <div className="flex-1">
                            <h4 className="font-medium text-gray-900">{doc.name}</h4>
                            <p className="text-sm text-gray-500 capitalize">{doc.type} • {doc.pages} pages</p>
                          </div>
                          <button className="text-indigo-600 hover:text-indigo-800 font-medium">
                            View
                          </button>
                        </div>
                      ))}
                      
                      {virtualBooks.map(book => (
                        <div 
                          key={book.id} 
                          className={`flex items-center p-4 border rounded-lg cursor-pointer transition duration-200 ${
                            selectedBook?.id === book.id 
                              ? 'border-indigo-500 bg-indigo-50' 
                              : 'border-gray-200 hover:bg-gray-50'
                          }`}
                          onClick={() => handleBookSelect(book)}
                        >
                          <div className="mr-4">
                            <BookOpen className="w-5 h-5 text-amber-600" />
                          </div>
                          <div className="flex-1">
                            <h4 className="font-medium text-gray-900">{book.title}</h4>
                            <p className="text-sm text-gray-500">Virtual Book • {book.pages} pages</p>
                          </div>
                          <button className="text-indigo-600 hover:text-indigo-800 font-medium">
                            Open
                          </button>
                        </div>
                      ))}
                    </div>
                    
                    {/* Document Viewer */}
                    {selectedDocument && (
                      <div className="border border-gray-200 rounded-lg p-4">
                        <div className="flex justify-between items-center mb-4">
                          <h3 className="font-bold text-gray-900">{selectedDocument.name}</h3>
                          <div className="flex space-x-2">
                            <button className="p-2 bg-gray-100 rounded-lg hover:bg-gray-200">
                              <Download className="w-4 h-4" />
                            </button>
                            <button className="p-2 bg-gray-100 rounded-lg hover:bg-gray-200">
                              <Upload className="w-4 h-4" />
                            </button>
                          </div>
                        </div>
                        
                        <div className="bg-gray-100 border border-gray-300 rounded-lg h-96 flex items-center justify-center">
                          <div className="text-center">
                            <FileText className="w-12 h-12 text-gray-400 mx-auto mb-4" />
                            <p className="text-gray-500">Document viewer for {selectedDocument.name}</p>
                            <p className="text-sm text-gray-400 mt-2">PDF content would be displayed here</p>
                          </div>
                        </div>
                        
                        <div className="flex justify-between items-center mt-4">
                          <div className="text-sm text-gray-500">
                            Page 1 of {selectedDocument.pages}
                          </div>
                          <div className="flex space-x-2">
                            <button className="p-2 bg-gray-100 rounded-lg hover:bg-gray-200">
                              <ZoomOut className="w-4 h-4" />
                            </button>
                            <span className="px-3 py-1 bg-gray-100 rounded-lg text-sm">100%</span>
                            <button className="p-2 bg-gray-100 rounded-lg hover:bg-gray-200">
                              <ZoomIn className="w-4 h-4" />
                            </button>
                          </div>
                        </div>
                      </div>
                    )}
                    
                    {/* Virtual Book Viewer */}
                    {selectedBook && (
                      <div className="border border-gray-200 rounded-lg">
                        <div className="flex justify-between items-center p-4 border-b border-gray-200">
                          <h3 className="font-bold text-gray-900">{selectedBook.title}</h3>
                          <div className="flex space-x-2">
                            <button 
                              className="p-2 bg-gray-100 rounded-lg hover:bg-gray-200"
                              onClick={handleAddBookmark}
                            >
                              <Bookmark className="w-4 h-4" />
                            </button>
                            <button className="p-2 bg-gray-100 rounded-lg hover:bg-gray-200">
                              <Download className="w-4 h-4" />
                            </button>
                            <button className="p-2 bg-gray-100 rounded-lg hover:bg-gray-200">
                              <Upload className="w-4 h-4" />
                            </button>
                          </div>
                        </div>
                        
                        <div className="flex">
                          {/* Bookmarks Sidebar */}
                          <div className="w-1/4 border-r border-gray-200 p-4">
                            <h4 className="font-medium text-gray-900 mb-3">Bookmarks</h4>
                            <div className="space-y-2">
                              {selectedBook.bookmarks.map(bookmark => (
                                <div 
                                  key={bookmark.id} 
                                  className="p-2 bg-gray-50 rounded-lg cursor-pointer hover:bg-gray-100"
                                  onClick={() => handlePageChange(bookmark.page)}
                                >
                                  <div className="flex justify-between">
                                    <span className="font-medium text-sm">{bookmark.label}</span>
                                    <button 
                                      className="text-gray-400 hover:text-red-500"
                                      onClick={(e) => {
                                        e.stopPropagation();
                                        handleRemoveBookmark(bookmark.id);
                                      }}
                                    >
                                      <X className="w-4 h-4" />
                                    </button>
                                  </div>
                                  <p className="text-xs text-gray-500">Page {bookmark.page}</p>
                                  {bookmark.note && (
                                    <p className="text-xs text-gray-600 mt-1">{bookmark.note}</p>
                                  )}
                                </div>
                              ))}
                            </div>
                          </div>
                          
                          {/* Book Content */}
                          <div className="flex-1">
                            <div className="p-4 border-b border-gray-200 flex justify-between items-center">
                              <div className="text-sm text-gray-500">
                                Page {selectedBook.currentPage} of {selectedBook.pages}
                              </div>
                              <div className="flex space-x-2">
                                <button 
                                  className="p-2 bg-gray-100 rounded-lg hover:bg-gray-200"
                                  onClick={() => handlePageChange(selectedBook.currentPage - 1)}
                                  disabled={selectedBook.currentPage <= 1}
                                >
                                  <ChevronLeft className="w-4 h-4" />
                                </button>
                                <button 
                                  className="p-2 bg-gray-100 rounded-lg hover:bg-gray-200"
                                  onClick={() => handlePageChange(selectedBook.currentPage + 1)}
                                  disabled={selectedBook.currentPage >= selectedBook.pages}
                                >
                                  <ChevronRight className="w-4 h-4" />
                                </button>
                                <button 
                                  className="p-2 bg-gray-100 rounded-lg hover:bg-gray-200"
                                  onClick={handleZoomOut}
                                >
                                  <ZoomOut className="w-4 h-4" />
                                </button>
                                <span className="px-3 py-1 bg-gray-100 rounded-lg text-sm">{zoomLevel}%</span>
                                <button 
                                  className="p-2 bg-gray-100 rounded-lg hover:bg-gray-200"
                                  onClick={handleZoomIn}
                                >
                                  <ZoomIn className="w-4 h-4" />
                                </button>
                                <button className="p-2 bg-gray-100 rounded-lg hover:bg-gray-200">
                                  <RotateCw className="w-4 h-4" />
                                </button>
                              </div>
                            </div>
                            
                            <div 
                              className="p-8 h-96 overflow-y-auto"
                              style={{ zoom: `${zoomLevel}%` }}
                            >
                              <div className="prose max-w-none">
                                <h2 className="text-xl font-bold mb-4">Page {selectedBook.currentPage}</h2>
                                <p>{selectedBook.content[selectedBook.currentPage - 1]}</p>
                              </div>
                            </div>
                          </div>
                        </div>
                      </div>
                    )}
                  </div>
                )}
                
                {/* Evidence Tab */}
                {activeTab === 'evidence' && (
                  <div className="space-y-6">
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                      <div className="border border-gray-200 rounded-lg p-4">
                        <div className="flex items-center mb-3">
                          <div className="w-10 h-10 bg-blue-100 rounded-lg flex items-center justify-center mr-3">
                            <FileText className="w-5 h-5 text-blue-600" />
                          </div>
                          <div>
                            <h4 className="font-medium text-gray-900">Digital Evidence</h4>
                            <p className="text-sm text-gray-500">3 items</p>
                          </div>
                        </div>
                        <button className="w-full text-left text-sm text-gray-600 hover:text-gray-900">
                          + Add Digital Evidence
                        </button>
                      </div>
                      
                      <div className="border border-gray-200 rounded-lg p-4">
                        <div className="flex items-center mb-3">
                          <div className="w-10 h-10 bg-green-100 rounded-lg flex items-center justify-center mr-3">
                            <FileText className="w-5 h-5 text-green-600" />
                          </div>
                          <div>
                            <h4 className="font-medium text-gray-900">Physical Evidence</h4>
                            <p className="text-sm text-gray-500">5 items</p>
                          </div>
                        </div>
                        <button className="w-full text-left text-sm text-gray-600 hover:text-gray-900">
                          + Add Physical Evidence
                        </button>
                      </div>
                      
                      <div className="border border-gray-200 rounded-lg p-4">
                        <div className="flex items-center mb-3">
                          <div className="w-10 h-10 bg-purple-100 rounded-lg flex items-center justify-center mr-3">
                            <FileText className="w-5 h-5 text-purple-600" />
                          </div>
                          <div>
                            <h4 className="font-medium text-gray-900">Witness Statements</h4>
                            <p className="text-sm text-gray-500">2 items</p>
                          </div>
                        </div>
                        <button className="w-full text-left text-sm text-gray-600 hover:text-gray-900">
                          + Add Statement
                        </button>
                      </div>
                    </div>
                    
                    <div className="border border-gray-200 rounded-lg p-4">
                      <h3 className="font-bold text-gray-900 mb-4">Evidence Log</h3>
                      <div className="space-y-3">
                        <div className="flex items-start p-3 bg-gray-50 rounded-lg">
                          <div className="w-8 h-8 bg-blue-100 rounded-full flex items-center justify-center mr-3 mt-1">
                            <FileText className="w-4 h-4 text-blue-600" />
                          </div>
                          <div>
                            <h4 className="font-medium text-gray-900">CCTV Footage Analysis</h4>
                            <p className="text-sm text-gray-600">Digital evidence showing subject entering storage room at 11:03 AM</p>
                            <div className="flex items-center mt-2">
                              <span className="inline-block bg-blue-100 text-blue-800 text-xs px-2 py-1 rounded">Digital</span>
                              <span className="ml-2 text-xs text-gray-500">Added 2 hours ago</span>
                            </div>
                          </div>
                        </div>
                        
                        <div className="flex items-start p-3 bg-gray-50 rounded-lg">
                          <div className="w-8 h-8 bg-green-100 rounded-full flex items-center justify-center mr-3 mt-1">
                            <FileText className="w-4 h-4 text-green-600" />
                          </div>
                          <div>
                            <h4 className="font-medium text-gray-900">Inventory Logs</h4>
                            <p className="text-sm text-gray-600">Digital records showing laptop marked as 'dispatched' at 9:47 AM</p>
                            <div className="flex items-center mt-2">
                              <span className="inline-block bg-green-100 text-green-800 text-xs px-2 py-1 rounded">Digital</span>
                              <span className="ml-2 text-xs text-gray-500">Added 1 day ago</span>
                            </div>
                          </div>
                        </div>
                      </div>
                    </div>
                  </div>
                )}
                
                {/* Notes Tab */}
                {activeTab === 'notes' && (
                  <div className="space-y-4">
                    <textarea
                      placeholder="Take notes during your session..."
                      className="w-full h-64 px-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent resize-none"
                    />
                    <div className="flex justify-end">
                      <button className="bg-indigo-600 text-white px-6 py-2 rounded-lg hover:bg-indigo-700 transition duration-300">
                        Save Notes
                      </button>
                    </div>
                  </div>
                )}
              </div>
            </div>
          </div>
          
          {/* Sidebar */}
          <div className="space-y-6">
            {/* Controls */}
            <div className="bg-white rounded-xl shadow-sm p-6 border border-gray-100">
              <h3 className="font-bold text-gray-900 mb-4">Courtroom Controls</h3>
              <div className="space-y-4">
                <button
                  onClick={toggleMute}
                  className="w-full flex items-center justify-center p-3 bg-gray-100 hover:bg-gray-200 rounded-lg transition duration-200"
                >
                  {isMuted ? <VolumeX className="w-5 h-5 mr-2" /> : <Volume2 className="w-5 h-5 mr-2" />}
                  {isMuted ? 'Unmute' : 'Mute'}
                </button>
                <button className="w-full flex items-center justify-center p-3 bg-gray-100 hover:bg-gray-200 rounded-lg transition duration-200">
                  <Pause className="w-5 h-5 mr-2" />
                  Pause Session
                </button>
                <button className="w-full flex items-center justify-center p-3 bg-indigo-600 text-white hover:bg-indigo-700 rounded-lg transition duration-300">
                  <Play className="w-5 h-5 mr-2" />
                  Resume Session
                </button>
              </div>
            </div>
            
            {/* Case Information */}
            <div className="bg-white rounded-xl shadow-sm p-6 border border-gray-100">
              <h3 className="font-bold text-gray-900 mb-4">Case Information</h3>
              <div className="space-y-3">
                <div>
                  <p className="text-sm text-gray-500">Case Type</p>
                  <p className="font-medium">Contract Dispute</p>
                </div>
                <div>
                  <p className="text-sm text-gray-500">Parties</p>
                  <p className="font-medium">Plaintiff vs. Defendant</p>
                </div>
                <div>
                  <p className="text-sm text-gray-500">Filed On</p>
                  <p className="font-medium">October 15, 2025</p>
                </div>
                <div>
                  <p className="text-sm text-gray-500">Status</p>
                  <span className="inline-block bg-green-100 text-green-800 text-xs font-medium px-2.5 py-0.5 rounded-full">
                    In Progress
                  </span>
                </div>
              </div>
            </div>
            
            {/* Timer */}
            <div className="bg-gradient-to-br from-indigo-500 to-purple-600 rounded-xl shadow-sm p-6 text-white">
              <h3 className="font-bold mb-2">Session Timer</h3>
              <div className="text-3xl font-mono font-bold">24:18</div>
              <p className="text-indigo-100 text-sm mt-1">Time elapsed</p>
              <div className="mt-4 w-full bg-white bg-opacity-20 rounded-full h-2">
                <div className="bg-white h-2 rounded-full" style={{ width: '45%' }}></div>
              </div>
              <p className="text-indigo-100 text-xs mt-2">45% of allocated time used</p>
            </div>
            
            {/* Bhagavad Gita Reference */}
            <div className="bg-amber-50 border border-amber-200 rounded-xl shadow-sm p-6">
              <div className="flex items-center mb-3">
                <BookOpen className="w-6 h-6 text-amber-700 mr-2" />
                <h3 className="font-bold text-amber-900">Reference Material</h3>
              </div>
              <p className="text-amber-800 text-sm mb-3">
                "Remember the teachings from the Bhagavad Gita about duty and truth."
              </p>
              <button 
                className="text-amber-700 hover:text-amber-900 text-sm font-medium flex items-center"
                onClick={() => {
                  const gitaBook = virtualBooks.find(b => b.id === 'bhagavad-gita');
                  if (gitaBook) {
                    handleBookSelect(gitaBook);
                  }
                }}
              >
                <Bookmark className="w-4 h-4 mr-1" />
                Open Reference
              </button>
            </div>
            
            {/* Voice Controls */}
            <div className="bg-white rounded-xl shadow-sm p-6 border border-gray-100">
              <h3 className="font-bold text-gray-900 mb-4">Voice Controls</h3>
              <div className="space-y-3">
                <div className="flex items-center justify-between">
                  <span className="text-sm text-gray-600">User Voice (Learned Counsel)</span>
                  <div className="flex space-x-2">
                    <button className="p-2 bg-gray-100 rounded-lg hover:bg-gray-200">
                      <PlayCircle className="w-4 h-4 text-indigo-600" />
                    </button>
                    <button className="p-2 bg-gray-100 rounded-lg hover:bg-gray-200">
                      <Square className="w-4 h-4 text-red-600" />
                    </button>
                  </div>
                </div>
                <div className="flex items-center justify-between">
                  <span className="text-sm text-gray-600">AI Voice (Hon'ble Court)</span>
                  <div className="flex space-x-2">
                    <button className="p-2 bg-gray-100 rounded-lg hover:bg-gray-200">
                      <PlayCircle className="w-4 h-4 text-green-600" />
                    </button>
                    <button className="p-2 bg-gray-100 rounded-lg hover:bg-gray-200">
                      <Square className="w-4 h-4 text-red-600" />
                    </button>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CourtroomSimulation;
